  ('disabled-c5fb3965-moex-00081', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-34c7f7f6', 'sub-disabled-c5fb3965-03', NULL, 'single_choice', '下列文句，用詞最為妥適、沒有語病的是：', '["我方在這場冠軍賽以凌厲的攻勢大敗對手，高舉金盃", "短時間之內要您拜讀本人的拙作，真是不勝犬馬怖懼之心", "陳先生熱心擔任銀行的白手套，幫忙處理大眾的慈善捐款", "老闆愛擺架子，藉此贏得屬下的敬重，此舉值得管理階層效法"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:55+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00082', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-34c7f7f6', 'sub-disabled-c5fb3965-03', NULL, 'single_choice', '某大樓發生深夜噪音的困擾，管理委員會張貼告示內容如下，那一選項的 用詞完全正確？', '["敝大樓諸位芳鄰您們好", "頃接獲敬啟者通報噪音", "茲考量彼此應敦睦邦誼", "敬祈深夜放輕腳步為禱"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:55+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00083', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-34c7f7f6', 'sub-disabled-c5fb3965-03', NULL, 'single_choice', '下列各政府機關宣傳標語的使用，何者最適當？', '["財政部：節約能源做得好，後代子孫沒煩惱", "法務部：飛來大獎莫驚喜，讓你掏錢洞無底", "勞動部：反貪不分你我他，廉能政府靠大家", "文化部：友善校園有正義，拒絕霸凌無畏懼"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:55+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00084', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-34c7f7f6', 'sub-disabled-c5fb3965-03', NULL, 'single_choice', '「如果你針對目標去努力，目標就會為你而實現。如果你針對計畫去努力， 計畫也會為你而奏效。」根據上文，下列選項何者最貼近文意？', '["事在人為", "自強不息", "孜孜不倦", "齊心戮力"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:55+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00085', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-34c7f7f6', 'sub-disabled-c5fb3965-03', NULL, 'single_choice', '「交通部航港局近年來為提升燈塔觀光價值，從去年將該高雄燈塔活化成 功打造為全國第一座夜間景觀燈塔後，再次選定高美燈塔規劃為全國第一 座提供泊宿服務燈塔。高美燈塔鄰近高美濕地，是全國唯一橫紋紅白相間、 八角形的燈塔，也是唯一成功復育綬草的燈塔園區，具有很高的觀光價 值。」 根據上文，最符合文意的選項是：', '["高雄燈塔是可供民眾泊宿新穎嘗試", "栽植綬草有助於凸顯高美濕地特色", "高美燈塔外觀造型和紋飾具獨特性", "高美濕地觀光價值取決於鄰近燈塔"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:55+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00086', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-34c7f7f6', 'sub-disabled-c5fb3965-03', NULL, 'single_choice', '有關「婚嫁」之題辭，下列選項錯誤的是：', '["「訂婚」：鳳毛濟美", "「結婚」：鸞鳳和鳴", "「結婚」：花好月圓", "「嫁女」：雀屏妙選"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:55+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00087', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-34c7f7f6', 'sub-disabled-c5fb3965-03', NULL, 'single_choice', '下列題辭與應用場合的配對，何者正確？', '["宜室宜家：新居落成", "道範長存：教師退休", "丕展鴻猷：官員升遷", "德門仁里：醫院開幕"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:55+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00088', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-34c7f7f6', 'sub-disabled-c5fb3965-03', NULL, 'single_choice', '「清代江南文化市場的發達，讓文人能夠把書畫、詩文等過去修身養性的 才藝，當作謀生之本，不必非要走上科舉出仕的道路。文人賣書畫昔已有 之，但以此為生，並形成職業群體，在這個環境下才真正成型，比如鄭板 橋辭官後，替自己的書畫標價，並不以言商為恥。」 根據上文，下列選項最符合文意的是：', '["清代以前的文人書畫家無不恥於出仕", "文人以書畫修身的傳統已在清代式微", "江南地區促成清代文人書畫的商品化", "從商對清代文人的吸引力遠大於科舉"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:55+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00089', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-34c7f7f6', 'sub-disabled-c5fb3965-03', NULL, 'single_choice', '「東郭子問莊子：所謂的『道』，究竟在什麼地方？莊子說：無所不在。 東郭子說：請你舉出具體的例子，清楚指明。莊子說：在螻蟻身上。東郭 子說：高妙的『道』，為什麼會在這樣卑下的地方呢？接著莊子又舉了愈 來愈卑下的例子，如：稊稗、磚瓦、屎溺。」（譯自《莊子．知北遊》） 根據上文，下列選項何者最符合莊子之意？', '["「道」是抽象而難以觀察的", "「道」要能脫離生活去體悟", "「道」只存在於卑微的事物中", "愈低微的事物，愈能看出「道」"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:55+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00090', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-34c7f7f6', 'sub-disabled-c5fb3965-03', NULL, 'single_choice', '「建築藝術自史前時代以來，便一直伴隨著人類。在建築以外，雖曾存在 許多藝術形式，但後來卻消失無蹤。如悲劇曾隨著古希臘人出現，後也因 為他們的沒落而消失，直到文藝復興時期才又再度活躍。這是因為人類一 直都有居住的需求，所以建築藝術從未被擱置一旁。人們會以二種方式來 接受建築物：透過使用和察覺；或更確切地說：透過觸覺和視覺。」 根據上文，下列選項正確的是：', '["人們透過觸覺和嗅覺感知建築藝術", "建築藝術因為古希臘人的沒落而一度中斷", "建築藝術一直伴隨著人類，因為人們有居住的需求", "藝術不曾消失，只是用另一種方式呈現於世人眼前"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:55+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL)
